import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { SignInForm } from '../components/Auth/SignInForm';
import { SignUpForm } from '../components/Auth/SignUpForm';
import { CheckInCodeInput } from '../components/Points/CheckInCodeInput';
import { supabase } from '../lib/supabase';
import { EventCard } from '../components/EventCard';
import { useEvents } from '../hooks/useEvents';

export function Home() {
  const { user } = useAuth();
  const [showSignUp, setShowSignUp] = useState(false);
  const [userName, setUserName] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const { events, loading: eventsLoading, error: eventsError } = useEvents();

  useEffect(() => {
    const fetchUserName = async () => {
      try {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) return;

        const { data: profile, error } = await supabase
          .from('user_profiles')
          .select('first_name, last_name')
          .eq('id', user.id)
          .single();

        if (error) throw error;
        if (profile) {
          setUserName(`${profile.first_name} ${profile.last_name}`);
        }
      } catch (err) {
        console.error('Error fetching user name:', err);
      } finally {
        setLoading(false);
      }
    };

    fetchUserName();
  }, []);

  if (loading) return <div>Loading...</div>;

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="bg-white rounded-lg shadow-lg p-8">
        <h1 className="text-4xl font-bold text-center mb-8">Welcome to VSA</h1>
        
        {user ? (
          <div className="space-y-8">
            <div className="text-center">
              <p className="text-xl mb-4">Hello, {userName || 'there'}!</p>
              <p className="text-gray-600 mb-6">You are signed in and ready to participate in events.</p>
              <div className="flex justify-center space-x-4">
                <a
                  href="/profile"
                  className="bg-gray-500 text-white px-6 py-2 rounded hover:bg-gray-600 transition-colors"
                >
                  View Profile
                </a>
              </div>
            </div>
            <div className="max-w-md mx-auto">
              <CheckInCodeInput />
            </div>
            <div className="mt-10">
              <h2 className="text-2xl font-bold mb-4 text-center">Upcoming Events</h2>
              {eventsLoading ? (
                <div className="text-center text-gray-500">Loading events...</div>
              ) : eventsError ? (
                <div className="text-center text-red-500">Error loading events: {eventsError.message}</div>
              ) : events.length === 0 ? (
                <div className="bg-white shadow rounded-lg p-6 text-center">
                  <p className="text-gray-600">No events scheduled at this time.</p>
                  <p className="text-gray-600 mt-2">Check back soon for upcoming events!</p>
                </div>
              ) : (
                <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
                  {events
                    .slice()
                    .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
                    .map(event => (
                      <EventCard
                        key={event.id}
                        event={event}
                        onCheckIn={() => {}}
                      />
                    ))}
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="text-center">
            <p className="text-xl mb-8">Please sign in or create an account to access events and track your points.</p>
            <div className="max-w-md mx-auto">
              {showSignUp ? (
                <>
                  <SignUpForm />
                  <p className="mt-4 text-gray-600">
                    Already have an account?{' '}
                    <button
                      onClick={() => setShowSignUp(false)}
                      className="text-indigo-600 hover:text-indigo-500"
                    >
                      Sign In
                    </button>
                  </p>
                </>
              ) : (
                <>
                  <SignInForm />
                  <p className="mt-4 text-gray-600">
                    Don't have an account?{' '}
                    <button
                      onClick={() => setShowSignUp(true)}
                      className="text-indigo-600 hover:text-indigo-500"
                    >
                      Sign Up
                    </button>
                  </p>
                </>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
